import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import './Css/Community.css';
import './Css/Landing.css';

const Community = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const username = location.state?.username || 'Gamer';

  const [posts, setPosts] = useState([]);
  const [newPost, setNewPost] = useState({ game_title: '', content: '', media_url: '', media_type: 'image' });

  const [activeTab, setActiveTab] = useState('feed'); 
  const [showProfile, setShowProfile] = useState(false);

  // --- NEW: CHAT & SEARCH STATES ---
  const [soloChats, setSoloChats] = useState([]); // Dynamic chat list (empty for now)
  const [squadChats, setSquadChats] = useState([]); 
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState([]);

  const fetchPosts = async () => {
    try {
      const res = await fetch('http://localhost:8000/api/community/posts');
      const data = await res.json();
      if (data.status === 'success') {
        setPosts(data.posts);
      }
    } catch (err) {
      console.error("Failed to fetch posts", err);
    }
  };

  useEffect(() => { fetchPosts(); }, []);

  const handlePostSubmit = async () => {
    if (!newPost.media_url) return alert("Please add an image or video URL!");
    try {
      const payload = { ...newPost, username };
      const res = await fetch('http://localhost:8000/api/community/posts', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });
      const data = await res.json();

      if (data.status === 'success') {
        setNewPost({ game_title: '', content: '', media_url: '', media_type: 'image' });
        fetchPosts(); 
        setActiveTab('feed'); 
      } else {
        alert("Failed to post: " + data.message);
      }
    } catch (err) { 
      alert("Network Error while posting."); 
    }
  };

  const handleLogout = () => navigate('/');

  // --- NEW: USER SEARCH LOGIC ---
  const handleSearchUsers = async (e) => {
    const query = e.target.value;
    setSearchQuery(query);

    if (query.trim().length > 0) {
      try {
        const res = await fetch(`http://localhost:8000/api/community/users/search?q=${query}&current_user=${username}`);
        const data = await res.json();
        if (data.status === 'success') {
          setSearchResults(data.users);
        }
      } catch (err) {
        console.error("Search failed", err);
      }
    } else {
      setSearchResults([]);
    }
  };

  const initiateChat = (targetUser) => {
    alert(`Opening chat with ${targetUser}... (Messaging feature coming next!)`);
    setSearchQuery('');
    setSearchResults([]);
  };

  return (
    <div className="community-shield">
      <header className="dash-header">
        <div className="logo" onClick={() => navigate('/landing', { state: { username } })} style={{ cursor: 'pointer' }}>GAMING<span>HUB</span></div>
        <nav className="dash-nav">
          <span onClick={() => navigate('/landing', { state: { username } })} style={{ cursor: 'pointer' }}>Home</span>
          <span className="active">The Nexus</span>
        </nav>

        <div className="profile-wrapper" onClick={() => setShowProfile(!showProfile)}>
          <div className="avatar">{username.charAt(0).toUpperCase()}</div>
          {showProfile && (
            <div className="profile-dropdown">
              <div className="dropdown-item" style={{color: '#fff', borderBottom: '1px solid #333'}}>
                Hi, <strong>{username}</strong>
              </div>
              <div className="dropdown-item">Profile</div>
              <div className="dropdown-item logout" onClick={handleLogout}>Logout</div>
            </div>
          )}
        </div>
      </header>

      <div className="community-layout">

        <aside className="comm-sidebar">
          <div className="comm-section-title">Main Hub</div>
          <div className={`comm-menu-item ${activeTab === 'feed' ? 'active' : ''}`} onClick={() => setActiveTab('feed')}>
            🌍 Nexus Feed
          </div>
          <div className={`comm-menu-item ${activeTab === 'create' ? 'active' : ''}`} onClick={() => setActiveTab('create')}>
            ✍️ Create Post
          </div>
          <div className="comm-menu-item">👤 My Profile</div>
          <div className="comm-menu-item">🔖 Saved Clips</div>

          <div className="comm-section-title" style={{marginTop: '30px'}}>Official Pages</div>
          <div className="comm-menu-item">⭐ Rockstar Games</div>
          <div className="comm-menu-item">⭐ CD Projekt Red</div>
          <div className="comm-menu-item">⭐ FromSoftware</div>
        </aside>

        <main className="comm-feed">
          {activeTab === 'create' && (
            <div className="create-post-box">
              <h3 style={{marginTop: 0, marginBottom: '20px', color: '#fff'}}>Create Transmission</h3>
              <input type="text" placeholder="What game are you playing?" value={newPost.game_title} onChange={e => setNewPost({...newPost, game_title: e.target.value})} />
              <textarea placeholder="Share a clip or drop a thought..." rows="3" value={newPost.content} onChange={e => setNewPost({...newPost, content: e.target.value})} />
              <div className="post-inputs-row">
                <input type="text" placeholder="Paste Image/Video URL here..." value={newPost.media_url} onChange={e => setNewPost({...newPost, media_url: e.target.value})} />
                <select value={newPost.media_type} onChange={e => setNewPost({...newPost, media_type: e.target.value})}>
                  <option value="image">Image</option>
                  <option value="video">Video (MP4)</option>
                </select>
              </div>
              <button className="post-btn" onClick={handlePostSubmit}>Transmit to Nexus</button>
              <div style={{ clear: 'both' }}></div>
            </div>
          )}

          {activeTab === 'feed' && (
            <>
              {posts.length === 0 ? <div className="no-posts">No transmissions found. Be the first!</div> : null}
              {posts.map(post => (
                <div key={post.id} className="post-card">
                  <div className="post-header">
                    <span className="post-author">@{post.username}</span>
                    {post.game_title && <span className="post-game-tag">{post.game_title}</span>}
                  </div>
                  {post.media_type === 'video' ? (
                    <video src={post.media_url} controls className="post-media" />
                  ) : (
                    <img src={post.media_url} alt="Post media" className="post-media" onError={(e) => { e.target.src = "https://via.placeholder.com/800x400?text=Invalid+Image+URL"; }} />
                  )}
                  {post.content && <div className="post-content">{post.content}</div>}
                  <div className="post-actions">
                    <button className="action-btn gg-btn">🔺 GG ({post.gg_count || 0})</button>
                    <button className="action-btn">💬 Comments</button>
                  </div>
                </div>
              ))}
            </>
          )}
        </main>

        <aside className="comm-chat-panel">

          <div className="chat-half">
            <div className="chat-header">Direct Messages</div>

            {/* NEW: Dynamic Search Bar */}
            <div className="chat-search-container">
              <input 
                type="text" 
                className="chat-search-input" 
                placeholder="Search gamers to text..." 
                value={searchQuery}
                onChange={handleSearchUsers}
              />

              {searchResults.length > 0 && (
                <div className="chat-search-results">
                  {searchResults.map(u => (
                    <div key={u.username} className="chat-search-item" onClick={() => initiateChat(u.username)}>
                      <div className="chat-avatar" style={{width: '28px', height: '28px', fontSize: '0.8rem'}}>
                        {u.username.charAt(0).toUpperCase()}
                      </div>
                      <span>{u.username}</span>
                    </div>
                  ))}
                </div>
              )}
            </div>

            <div className="chat-list">
              {soloChats.length === 0 ? (
                <div className="empty-chat-msg">No active messages. Use the search bar to find gamers and start chatting!</div>
              ) : (
                soloChats.map(chat => (
                  <div key={chat.id} className="chat-user">
                    <div className="chat-avatar">{chat.name.charAt(0)}</div>
                    <div className="chat-user-info">
                      <span>{chat.name} {chat.online && <div className="online-dot"></div>}</span>
                      <small>{chat.lastMsg}</small>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>

          <div className="chat-half">
            <div className="chat-header">My Squads</div>
            <div className="chat-list">
              {squadChats.length === 0 ? (
                <div className="empty-chat-msg">You haven't joined any squads yet. Create one or look out for invites.</div>
              ) : (
                squadChats.map(chat => (
                  <div key={chat.id} className="chat-user">
                    <div className="chat-avatar squad-icon">🛡️</div>
                    <div className="chat-user-info">
                      <span>{chat.name}</span>
                      <small>{chat.lastMsg}</small>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        </aside>

      </div>
    </div>
  );
};

export default Community;
